,"end_date":"2026-07-06","cie10_code":"S019","diagnosis":"Herida De La Cabeza, Parte No Especificada","is_extension":false,"prorroga_original":"NO","filing_date":"2026-06-24","employer_amount":null,"payer_amount":null,"recovered_amount":null,"actual_payment_date":null,"recovery_status":"radicado","valid_excel_dates":true,"date_issue":null},{"excel_row":415,"doc":"1098639918","tipo_original":"Licencia de Maternidad","origin":"licencia_maternidad","certificate_number":"Transcripcion: 2510868\nINCP2510868","days":126,"start_date":"2026-06-04","end_date":"2026-10-07","cie10_code":"O829","diagnosis":"Parto Por Cesarea, Sin Otra Especificacion","is_extension":false,"prorroga_original":"NO","filing_date":"2026-06-11","employer_amount":null,"payer_amount":null,"recovered_amount":null,"actual_payment_date":null,"recovery_status":"radicado","valid_excel_dates":true,"date_issue":null},{"excel_row":416,"doc":"1005338656","tipo_original":"Licencia de Maternidad","origin":"licencia_maternidad","certificate_number":"FALTA HC","days":126,"start_date":"2026-06-12","end_date":"2026-10-14","cie10_code":"O800","diagnosis":"Parto Unico Espontaneo, Presentacion Cefalica De Vertice","is_extension":false,"prorroga_original":"NO","filing_date":null,"employer_amount":null,"payer_amount":null,"recovered_amount":null,"actual_payment_date":null,"recovery_status":"radicado","valid_excel_dates":false,"date_issue":"days_mismatch_calc_125"}]$payload$::jsonb) as r(
    excel_row int,
    doc text,
    tipo_original text,
    origin text,
    certificate_number text,
    days int,
    start_date text,
    end_date text,
    cie10_code text,
    diagnosis text,
    is_extension boolean,
    prorroga_original text,
    filing_date text,
    employer_amount numeric,
    payer_amount numeric,
    recovered_amount numeric,
    actual_payment_date text,
    recovery_status text,
    valid_excel_dates boolean,
    date_issue text
  )
), petro as (
  select id as company_id from public.companies where name = 'Petrocasinos S.A.'
), employee_matches as (
  select
    raw.doc,
    count(e.id)::int as match_count,
    (array_agg(e.id) filter (where e.id is not null))[1] as employee_id
  from (select distinct doc from raw where doc is not null) raw
  left join public.employees_v2 e
    on regexp_replace(e.document_number, '\D', '', 'g') = raw.doc
   and e.company_id = (select company_id from petro)
  group by raw.doc
), prepared as (
  select
    r.*,
    p.company_id,
    em.employee_id,
    em.match_count,
    ss.eps,
    ss.arl,
    ss.afp,
    case
      when not coalesce(r.valid_excel_dates, false) then 'invalid_dates_or_days'
      when coalesce(em.match_count, 0) = 0 then 'employee_not_found'
      when em.match_count > 1 then 'ambiguous_employee_document'
      else null
    end as skip_reason
  from raw r
  cross join petro p
  left join employee_matches em on em.doc = r.doc
  left join lateral (
    select eps, arl, afp
    from public.employee_social_security s
    where s.employee_id = em.employee_id
      and coalesce(s.is_current, false) = true
    order by s.updated_at desc nulls last, s.created_at desc nulls last
    limit 1
  ) ss on true
), insertable as (
  select p.*
  from prepared p
  where p.skip_reason is null
    and not exists (
      select 1
      from public.employee_incapacities ei
      where ei.company_id = p.company_id
        and ei.employee_id = p.employee_id
        and ei.start_date = p.start_date::date
        and ei.end_date = p.end_date::date
        and coalesce(ei.cie10_code, '') = coalesce(p.cie10_code, '')
        and coalesce(ei.certificate_number, '') = coalesce(p.certificate_number, '')
    )
), duplicated_existing as (
  select p.*
  from prepared p
  where p.skip_reason is null
    and exists (
      select 1
      from public.employee_incapacities ei
      where ei.company_id = p.company_id
        and ei.employee_id = p.employee_id
        and ei.start_date = p.start_date::date
        and ei.end_date = p.end_date::date
        and coalesce(ei.cie10_code, '') = coalesce(p.cie10_code, '')
        and coalesce(ei.certificate_number, '') = coalesce(p.certificate_number, '')
    )
), inserted as (
  insert into public.employee_incapacities (
    employee_id,
    company_id,
    origin,
    start_date,
    end_date,
    cie10_code,
    diagnosis,
    certificate_number,
    eps_name,
    arl_name,
    afp_name,
    employer_days,
    eps_days,
    arl_days,
    afp_days,
    employer_amount,
    eps_amount,
    arl_amount,
    afp_amount,
    total_amount,
    recovery_status,
    filing_date,
    filing_number,
    actual_payment_date,
    recovered_amount,
    recovery_notes,
    is_extension,
    parent_incapacity_id,
    extension_number,
    requires_reintegration_exam,
    observations
  )
  select
    employee_id,
    company_id,
    origin::public.incapacity_origin,
    start_date::date,
    end_date::date,
    nullif(cie10_code, ''),
    diagnosis,
    nullif(certificate_number, ''),
    eps,
    arl,
    afp,
    case when origin in ('comun', 'accidente_transito') then least(days, 2) else 0 end,
    case when origin in ('licencia_maternidad', 'licencia_paternidad') then days when origin in ('comun', 'accidente_transito') then greatest(days - least(days, 2), 0) else 0 end,
    case when origin = 'laboral' then days else 0 end,
    0,
    coalesce(employer_amount, 0),
    case when origin = 'laboral' then 0 else coalesce(payer_amount, 0) end,
    case when origin = 'laboral' then coalesce(payer_amount, 0) else 0 end,
    0,
    coalesce(employer_amount, 0) + coalesce(payer_amount, 0),
    recovery_status::public.recovery_status,
    filing_date::date,
    nullif(certificate_number, ''),
    actual_payment_date::date,
    coalesce(recovered_amount, 0),
    'Importado desde incapacidad 2026.xlsx. Fila Excel: ' || excel_row || '. Tipo original: ' || coalesce(tipo_original, '') || '. Prórroga Excel: ' || coalesce(prorroga_original, ''),
    coalesce(is_extension, false),
    null,
    0,
    days > 30,
    'Importado desde incapacidad 2026.xlsx. Fila Excel: ' || excel_row || '. Valores originales: empresa=' || coalesce(employer_amount::text, '0') || ', entidad=' || coalesce(payer_amount::text, '0') || ', pagado=' || coalesce(recovered_amount::text, '0')
  from insertable
  returning id
)
select jsonb_pretty(jsonb_build_object(
  'raw_rows', (select count(*) from raw),
  'inserted_rows', (select count(*) from inserted),
  'skipped_existing_duplicates', (select count(*) from duplicated_existing),
  'skipped_invalid_dates_or_days', (select count(*) from prepared where skip_reason = 'invalid_dates_or_days'),
  'skipped_employee_not_found', (select count(*) from prepared where skip_reason = 'employee_not_found'),
  'skipped_ambiguous_employee_document', (select count(*) from prepared where skip_reason = 'ambiguous_employee_document'),
  'exception_docs', (select coalesce(jsonb_agg(distinct doc order by doc) filter (where skip_reason in ('employee_not_found','ambiguous_employee_document')), '[]'::jsonb) from prepared),
  'invalid_date_rows', (select coalesce(jsonb_agg(jsonb_build_object('excel_row', excel_row, 'doc', doc, 'issue', date_issue) order by excel_row) filter (where skip_reason = 'invalid_dates_or_days'), '[]'::jsonb) from prepared)
)) as import_summary;
